#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007
#define MAXN 300000

// Define the structure for a tree node
typedef struct Node {
    int val;
    int numChildren;
    struct Node** children;
} Node;

// Function to create a new tree node
Node* createNode(int val) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->val = val;
    node->numChildren = 0;
    node->children = NULL;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**) realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to calculate the beauty of a subtree
long long calculateBeauty(Node* node) {
    if (node->numChildren == 0) {
        return 1;
    }
    long long beauty = 0;
    for (int i = 0; i < node->numChildren; i++) {
        beauty += calculateBeauty(node->children[i]);
    }
    return (beauty * 2) % MOD;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        Node** nodes = (Node**) malloc(N * sizeof(Node*));
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addChild(nodes[u - 1], nodes[v - 1]);
        }
        for (int i = 0; i < N; i++) {
            printf("%lld\n", calculateBeauty(nodes[i]) % MOD);
        }
        free(nodes);
    }
    return 0;
}

