#include <iostream>
#include <vector>
using namespace std;
#define MOD 1000000007
#define MAXN 300000

// Define the structure for a tree node
struct Node {
    int val;
    vector<Node*> children;
};

// Function to create a new tree node
Node* createNode(int val) {
    Node* node = new Node;
    node->val = val;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->children.push_back(child);
}

// Function to calculate the beauty of a subtree
long long calculateBeauty(Node* node) {
    if (node->children.empty()) {
        return 1;
    }
    long long beauty = 0;
    for (Node* child : node->children) {
        beauty += calculateBeauty(child);
    }
    return (beauty * 2) % MOD;
}

int main() {
    int T;
    cin >> T;
    for (int t = 0; t < T; t++) {
        int N;
        cin >> N;
        Node** nodes = new Node*[N];
        for (int i = 0; i < N; i++) {
            nodes[i] = createNode(i + 1);
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            cin >> u >> v;
            addChild(nodes[u - 1], nodes[v - 1]);
        }
        for (int i = 0; i < N; i++) {
            cout << calculateBeauty(nodes[i]) % MOD << endl;
        }
        delete[] nodes;
    }
