import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class Main {
    static final int MOD = 1000000007;
    static final int MAXN = 300000;
    // Define the structure for a tree node
    static class Node {
        int val;
        List<Node> children;
        Node(int val) {
            this.val = val;
            this.children = new ArrayList<>();
        }
    }
    // Function to add a child to a node
    static void addChild(Node node, Node child) {
        node.children.add(child);
    }
    // Function to calculate the beauty of a subtree
    static long calculateBeauty(Node node) {
        if (node.children.isEmpty()) {
            return 1;
        }
        long beauty = 0;
        for (Node child : node.children) {
            beauty += calculateBeauty(child);
        }
        return (beauty * 2) % MOD;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            Node[] nodes = new Node[N];
            for (int i = 0; i < N; i++) {
                nodes[i] = new Node(i + 1);
            }
            for (int i = 0; i < N - 1; i++) {
                int u = scanner.nextInt();
                int v = scanner.nextInt();
                addChild(nodes[u - 1], nodes[v - 1]);
            }
            for (int i = 0; i < N; i++) {
                System.out.println(calculateBeauty(nodes[i]) % MOD);
            }
        }
    }
